@implementation AccountViewController

- (instancetype)init {
    self = [super init];
    if (self) {
        self.view.backgroundColor = BACKGROUND_COLOR;
        self.types = [TypeModel allTypes];
        self.displaytypes = [self.types mutableCopy];
        self.modalPresentationStyle = UIModalPresentationFullScreen;

    }
    return self;
}

- (void)viewDidLoad {
    [super viewDidLoad];
    UIBarButtonItem *editButton = [[UIBarButtonItem alloc] initWithImage:[UIImage imageNamed:@"A_Main_AddButton"]
