        backgroundImageView.layer.cornerRadius = ZOOMW(16);
        backgroundImageView.clipsToBounds = YES;
        cell.backgroundView = backgroundImageView;
    }
    backgroundImageView.image = [UIImage imageNamed:[NSString stringWithFormat:@"A_%@", self.displaytypes[indexPath.item].type]];

    return cell;
}

