- (void)saveAccount:(UIButton *)sender {
    NSString *type = [self.typeValueLabel.text stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
    NSString *name = [self.nameTextField.text stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
    NSString *account = [self.accountTextField.text stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
    NSString *password = [self.passwordTextField.text stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
    NSString *note = [self.noteTextField.text stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];

    if (type.length == 0 || name.length == 0 || account.length == 0 || password.length == 0) {
        [SVProgressHUD showErrorWithStatus:NSLocalizedString(@"请填写完整信息", nil)];
        return;
    }

    self.Account.type = type;
    self.Account.name = name;
    self.Account.account = account;
    self.Account.password = password;
    self.Account.note = note;
    self.Account.updateTime = [NSDate date];



    if (self.isNewAcc) {
        self.Account.createTime = [NSDate date];
        [AccountModel addAcc:self.Account];
        [[NSNotificationCenter defaultCenter] postNotificationName:@"AccountDataUpdated" object:nil];
        [[NSNotificationCenter defaultCenter] postNotificationName:@"SwitchToAccountTab" object:nil];
    } else {
        [AccountModel updateAcc:self.Account];
        [[NSNotificationCenter defaultCenter] postNotificationName:@"AccountDataUpdated" object:nil];
        [self dismissViewControllerAnimated:YES completion:nil];
    }


    [self dismissViewControllerAnimated:YES completion:nil];
}

