@implementation TypeViewController

- (instancetype)init{
    self = [super init];
    if (self) {
        self.isSearching = YES;
        self.text = NSLocalizedString(@"搜索", nil);
        self.displayAccs = [AccountModel allAccs];
        self.view.backgroundColor = BACKGROUND_COLOR;
        self.modalPresentationStyle = UIModalPresentationFullScreen;
    }
    return self;
}

- (instancetype)initWithType:(TypeModel *)type{
    self = [super init];
    if (self) {
        self.isSearching = NO;
        self.Type = type;
        self.text = NSLocalizedString(type.type, nil);
        self.view.backgroundColor = BACKGROUND_COLOR;
        self.modalPresentationStyle = UIModalPresentationFullScreen;
        NSPredicate *predicate = [NSPredicate predicateWithFormat:@"type == %@", self.text];
        NSArray *filteredArray = [[AccountModel allAccs] filteredArrayUsingPredicate:predicate];
        self.displayAccs = [filteredArray mutableCopy];
        [TypeModel updateType:self.Type];
    }
    return self;
}


- (void)viewDidLoad {
    [super viewDidLoad];
    self.emptyLabel = [[UILabel alloc] init];
    self.emptyLabel.text = @"暂无账号，请添加后再试";
    self.emptyLabel.hidden = YES;
    self.emptyLabel.textColor = RGBA(102, 102, 102, 1);
    [self setupUI];
    [self loadData];
    [self.headerView showAppearAnimation];
    if (self.displayAccs.count == 0) {
        self.collectionView.hidden = YES;
    }
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(handleAccountUpdate) name:@"AccountDataUpdated" object:nil];
}

- (void)loadData {
    if (self.isSearching) {

    } else {
        NSPredicate *predicate = [NSPredicate predicateWithFormat:@"type == %@", self.text];
        NSArray *filteredArray = [[AccountModel allAccs] filteredArrayUsingPredicate:predicate];
        self.displayAccs = [filteredArray mutableCopy];
    }
    [self.collectionView reloadData];
}

- (void)setupUI {

    [self.view addSubview:self.headerView];
    [self.view addSubview:self.collectionView];

    [_headerView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.view);
        make.left.equalTo(self.view);
        make.right.equalTo(self.view);
        make.bottom.equalTo(self.view).offset(ZOOM(-724));
    }];
    [self.collectionView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.headerView.mas_bottom).offset(ZOOMW(20));
        make.left.right.bottom.equalTo(self.view);
    }];
}

- (void)handleAccountUpdate {

    [self loadData];
}

#pragma mark - UICollectionView DataSource & Delegate
- (NSInteger)collectionView:(UICollectionView *)collectionView numberOfItemsInSection:(NSInteger)section {
    return self.displayAccs.count;
}

- (UICollectionViewCell *)collectionView:(UICollectionView *)collectionView cellForItemAtIndexPath:(NSIndexPath *)indexPath {
    AccCell *cell = [collectionView dequeueReusableCellWithReuseIdentifier:@"AccCell" forIndexPath:indexPath];

    AccountModel *account = self.displayAccs[indexPath.item];
    cell.Account = account;
    cell.nameLabel.text = account.name;
    cell.noteLabel.text = account.note;

    return cell;
}

- (void)collectionView:(UICollectionView *)collectionView didSelectItemAtIndexPath:(NSIndexPath *)indexPath {

    AccountAddViewController *Aavc = [[AccountAddViewController alloc] initWithAccount:self.displayAccs[indexPath.item]];
    [self presentViewController:Aavc animated:YES completion:nil];

}

- (CGSize)collectionView:(UICollectionView *)collectionView layout:(UICollectionViewLayout *)collectionViewLayout sizeForItemAtIndexPath:(NSIndexPath *)indexPath {
    return CGSizeMake(ZOOMW(343), ZOOMW(70));
