- (CGFloat)getImageCellHeightForSize:(CGSize)imageSize {
    CGFloat ratio = (imageSize.height > 0.0f) ? (imageSize.width / imageSize.height) : 0.0f;
    CGFloat fixedWidth = (ratio > 1.0f) ? ZOOMW(220) : ZOOMW(160);
    CGFloat maxWidth = CGRectGetWidth(UIScreen.mainScreen.bounds) * 0.72f;
    CGFloat width = (ratio > 0.0f) ? MIN(fixedWidth, maxWidth) : ZOOMW(160);
    CGFloat height = (ratio > 0.0f) ? (width / ratio) : ZOOMW(180);
    return height + ZOOM(32);
}

