- (NSInteger)getStringWidthToCellHeight:(NSString *)string {
    // 将文本分割为行
    NSArray *lines = [string componentsSeparatedByString:@"\n"];

    // 计算空行数
    NSPredicate *isEmptyLinePredicate = [NSPredicate predicateWithBlock:^BOOL(id _Nullable evaluatedObject, NSDictionary * _Nullable bindings) {
        return ([evaluatedObject isKindOfClass:[NSString class]] && [(NSString *)evaluatedObject length] == 0);
    }];
    NSArray *emptyLines = [lines filteredArrayUsingPredicate:isEmptyLinePredicate];
    NSInteger emptyLineCount = (NSInteger)emptyLines.count;

    // 使用系统字体进行计算
    UIFont *font = [UIFont systemFontOfSize:16.0];

    // 计算实际文本的行数
    CGFloat totalTextHeight = 0.0;
    for (NSString *line in lines) {
        if (![emptyLines containsObject:line]) { // 只处理非空行
            // 使用boundingRect来计算文本占用的实际高度
            CGSize maxSize = CGSizeMake(ZOOM(260), CGFLOAT_MAX);  // 最大宽度

            CGRect textRect = [line boundingRectWithSize:maxSize
                                                 options:NSStringDrawingUsesLineFragmentOrigin
                                              attributes:@{NSFontAttributeName: font}
                                                 context:nil];
            // 每一行的高度由文本占用的高度决定
            totalTextHeight += textRect.size.height;
        }
    }

    // 计算 cell 的总高度
    CGFloat cellHeight = totalTextHeight              // 计算所有文本行的总高度
    + emptyLineCount * ZOOM(19)  // 计算空行的高度，这里空行的计算是不准确的，但是在代码里进行了去空行的操作
    + ZOOM(40);                  // 添加气泡上下的间距（已涵盖所有间距）
    NSLog(@"cellHeight:%lf",cellHeight-ZOOM(40));
    return cellHeight;
}

