@implementation AccountViewController

- (NSArray<TypeModel *> *)visibleTypesFromTypes:(NSArray<TypeModel *> *)types {
    NSArray<NSString *> *orderedTypeNames = @[@"Social", @"Mail", @"Game"];
    NSMutableArray<TypeModel *> *visibleTypes = [NSMutableArray array];

    for (NSString *typeName in orderedTypeNames) {
        NSPredicate *predicate = [NSPredicate predicateWithFormat:@"type == %@", typeName];
        TypeModel *matchedType = [[types filteredArrayUsingPredicate:predicate] firstObject];
        if (matchedType) {
            [visibleTypes addObject:matchedType];
        }
    }

    return visibleTypes;
}

- (instancetype)init {
    self = [super init];
    if (self) {
        self.view.backgroundColor = RGBA(220, 232, 244, 1);
        self.types = [TypeModel allTypes];
        self.displaytypes = [[self visibleTypesFromTypes:self.types] mutableCopy];
        self.modalPresentationStyle = UIModalPresentationFullScreen;

    }
    return self;
}

